import{_ as o,o as e,c as r,ae as a}from"./chunks/framework.6gkcVjOI.js";const u=JSON.parse('{"title":"概述","description":"什么是 claude-code-Go？了解这个 Go 实现的 Claude Code 及其核心架构","frontmatter":{"title":"概述","description":"什么是 claude-code-Go？了解这个 Go 实现的 Claude Code 及其核心架构"},"headers":[],"relativePath":"zh/guide/introduction.md","filePath":"zh/guide/introduction.md","lastUpdated":1775357776000}'),d={name:"zh/guide/introduction.md"};function l(n,t,i,s,h,c){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h1><p>欢迎了解 claude-code-Go——一个用 Go 语言实现的 Claude Code 智能体系统。</p><h2 id="什么是-claude-code-go" tabindex="-1">什么是 claude-code-Go？ <a class="header-anchor" href="#什么是-claude-code-go" aria-label="Permalink to &quot;什么是 claude-code-Go？&quot;">​</a></h2><p>claude-code-Go 是一个终端驱动的 AI 编程助手，完整实现了 Agent Loop（智能体循环），包含内置工具系统、三级权限管理、MCP（Model Context Protocol）协议支持以及 SSE（Server-Sent Events）流式输出。</p><p>核心设计理念：<strong>模型提供智能，Harness 提供可靠性</strong>。</p><p>LLM 负责理解意图、决策工具调用、解释执行结果；运行时负责权限控制、超时保护、输出截断、会话持久化——确保系统达到生产级可靠性标准。</p><p>你可以把它理解为：</p><ul><li>一个能读取、编写、编辑项目文件的 AI 助手</li><li>一个能执行 shell 命令、运行构建和测试的自动化工具</li><li>一个能用 glob 模式和内容搜索浏览代码库的代码导航器</li><li>一个在终端 REPL 中与你协作编程的智能体</li></ul><h2 id="它和普通聊天机器人有什么不同" tabindex="-1">它和普通聊天机器人有什么不同？ <a class="header-anchor" href="#它和普通聊天机器人有什么不同" aria-label="Permalink to &quot;它和普通聊天机器人有什么不同？&quot;">​</a></h2><p>与传统的聊天机器人不同，claude-code-Go 作为一个具有自主能力和工具使用能力的<strong>智能体</strong>运作。</p><table tabindex="0"><thead><tr><th>特性</th><th>聊天机器人</th><th>claude-code-Go</th></tr></thead><tbody><tr><td><strong>交互模式</strong></td><td>请求-响应</td><td>持续智能体循环，自主调用工具</td></tr><tr><td><strong>能力边界</strong></td><td>仅文本生成</td><td>读取、编写、编辑、执行、搜索</td></tr><tr><td><strong>状态管理</strong></td><td>无状态</td><td>消息历史 + 上下文自动压缩</td></tr><tr><td><strong>用户控制</strong></td><td>被动接收</td><td>危险操作需主动审批（y/n/a）</td></tr><tr><td><strong>使用场景</strong></td><td>问答、对话</td><td>代码开发、重构、调试、自动化</td></tr></tbody></table><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><p>claude-code-Go 遵循最小依赖原则构建：</p><table tabindex="0"><thead><tr><th>组件</th><th>技术</th></tr></thead><tbody><tr><td><strong>编程语言</strong></td><td>Go 1.23+</td></tr><tr><td><strong>运行时依赖</strong></td><td>零外部依赖（纯 Go 标准库）</td></tr><tr><td><strong>Python 测试框架</strong></td><td>可选（harness/ 目录，用于测试、模拟、评估）</td></tr><tr><td><strong>API 协议</strong></td><td>Anthropic Messages API + SSE 流式传输</td></tr></tbody></table><p><code>harness/</code> 目录下的 Python 测试框架是可选的，提供：</p><ul><li>Mock API 服务器（测试时无需 API 费用）</li><li>会话回放（用于调试和 Trace 分析）</li><li>质量评估器（用于集成测试）</li></ul><h2 id="核心数字" tabindex="-1">核心数字 <a class="header-anchor" href="#核心数字" aria-label="Permalink to &quot;核心数字&quot;">​</a></h2><ul><li><strong>~30</strong> 个 Go 源文件（非测试）</li><li><strong>~4,000</strong> 行 Go 代码</li><li><strong>~2,000</strong> 行 Python 代码（harness）</li><li><strong>8</strong> 个内部模块</li><li><strong>6</strong> 个内置工具（Read、Write、Edit、Glob、Grep、Bash）</li></ul><h2 id="你将学到什么" tabindex="-1">你将学到什么 <a class="header-anchor" href="#你将学到什么" aria-label="Permalink to &quot;你将学到什么&quot;">​</a></h2><p>本文档涵盖 claude-code-Go 的架构和实现细节：</p><ol><li><strong>AI 智能体架构</strong> — Agent Loop 的工作原理、stop_reason 驱动的状态机、工具选择策略</li><li><strong>流式 API 集成</strong> — SSE 协议解析、token 级流式输出、HTTP 重试机制</li><li><strong>工具系统设计</strong> — Tool 接口抽象、Registry 模式、MCP 协议集成</li><li><strong>安全架构</strong> — 三级权限模型、glob 规则匹配、Human-in-the-loop 审批</li><li><strong>工程实践</strong> — 结构化日志、信号处理、配置管理、上下文压缩</li></ol><h2 id="目标读者" tabindex="-1">目标读者 <a class="header-anchor" href="#目标读者" aria-label="Permalink to &quot;目标读者&quot;">​</a></h2><p>本文档面向：</p><ul><li>对构建 AI 驱动工具感兴趣的 <strong>Go 开发者</strong></li><li>对 Agent 架构好奇的 <strong>系统程序员</strong></li><li>寻求 CLI 自动化方案的 <strong>DevOps 工程师</strong></li><li>探索 LLM 应用模式的 <strong>技术架构师</strong></li></ul><p>前置知识：</p><ul><li>Go 编程语言基础</li><li>终端/命令行操作</li><li>HTTP API 和 JSON 数据格式</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>前往<a href="./quick-start.html">快速开始</a>运行你的第一个命令。</p><p>或深入<a href="./../architecture/overview.html">架构概览</a>理解各模块如何协同工作。</p>',29)])])}const p=o(d,[["render",l]]);export{u as __pageData,p as default};
